+        }
+
+        if !self
+            .pane_selection
+            .anchor
+            .is_some_and(|anchor| self.pane_selection.selected.contains(&anchor))
+        {
+            self.pane_selection.anchor = self.pane_selection.selected.iter().next().copied();
+        }
+    }
